"use strict";parserFactory.register("wfxs.tw",()=>new WfxsParser);class WfxsParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=this.makeTocUrl(e.baseURI),r=[...(await HttpClient.wrapFetch(t)).responseXML.querySelectorAll("#readerlists")].pop();return util.hyperlinksToChapterList(r)}makeTocUrl(e){return e.substring(0,e.length-1).replace("xiaoshuo","booklist")+".html"}findContent(e){return Parser.findConstrutedContent(e)}extractTitleImpl(e){return e.querySelector(".booktitle h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"#bookimg")}async fetchChapter(e){let t=Parser.makeEmptyDocForContent(e),r=(await HttpClient.wrapFetch(e)).responseXML;t.content.appendChild(this.findRawContent(r));let n=this.findNextPageUrl(r);for(;null!=n;)r=(await HttpClient.wrapFetch(n)).responseXML,t.content.appendChild(this.findRawContent(r)),n=this.findNextPageUrl(r);return t.dom}findRawContent(e){return e.querySelector(".chapter-content")}findNextPageUrl(e){let t=[...e.querySelectorAll(".foot-nav a")].map(e=>e.href)[2];return null!=t&&t.endsWith(".html")?t:null}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("#intro_win p")]}}